/* == EXEMPLE ================================================
 * Decomposer le chemin /etc/network/interfaces
 * basename() donne le nom, dirname() le repertoire parent.
 * IMPORTANT: ces fonctions modifient leur argument.
 * =========================================================== */
void example_decompose(void) {
    const char *p = "/etc/network/interfaces";
    char b1[256], b2[256];
    strncpy(b1, p, sizeof(b1) - 1); b1[255] = '\0';
    strncpy(b2, p, sizeof(b2) - 1); b2[255] = '\0';
    printf("basename: %s\n", basename(b1));  /* interfaces */
    printf("dirname:  %s\n", dirname(b2));   /* /etc/network */
}
